9632           // (X << C) or (X >>_s C) or (X >>_u C).
9633           if (match(A, m_BitwiseLogic(m_Value(X), m_ConstantInt())) ||
9634               match(A, m_Shift(m_Value(X), m_ConstantInt())))
9635             AddAffected(X);
9636           else if (match(A, m_And(m_Value(X), m_Value(Y))) ||
9637                    match(A, m_Or(m_Value(X), m_Value(Y)))) {
9638             AddAffected(X);
9639             AddAffected(Y);
9640           }
9641         }
9642       } else {
9643         if (match(B, m_ConstantInt())) {
9644           // Handle (A + C1) u< C2, which is the canonical form of
9645           // A > C3 && A < C4.
9646           if (match(A, m_AddLike(m_Value(X), m_ConstantInt())))
9647             AddAffected(X);
9648 
9649           if (ICmpInst::isUnsigned(Pred)) {
9650             Value *Y;
9651             // X & Y u> C    -> X >u C && Y >u C
9652             // X | Y u< C    -> X u< C && Y u< C
9653             // X nuw+ Y u< C -> X u< C && Y u< C
9654             if (match(A, m_And(m_Value(X), m_Value(Y))) ||
9655                 match(A, m_Or(m_Value(X), m_Value(Y))) ||
9656                 match(A, m_NUWAdd(m_Value(X), m_Value(Y)))) {
